### Load cfbfastR data for Portal and baseball 


::: {.cell}

```{.r .cell-code}
library(rlang)
library(cbbplotR)
options(chromote.headless = "new")

portal <- cfbfastR::cfbd_recruiting_transfer_portal(2025) |> 
  dplyr::mutate(
    transfer_date = as.Date(transfer_date),
    transfer_month = lubridate::month(transfer_date, label = TRUE),
    transfer_year = lubridate::year(transfer_date),
    rating = as.numeric(rating),
    window = ifelse(transfer_month != "Apr", "Winter", "Spring"),
    position = ifelse(position == "ATH", "QB", position),
    position = forcats::fct_infreq(position) |> forcats::fct_rev(),
    rating_tier = dplyr::case_when(
      rating >= 0.95 ~ "Elite",
      rating >= 0.90 ~ "High",
      rating >= 0.85 ~ "Solid",
      TRUE ~ "Depth"
    )
  ) |> 
  dplyr::filter(!is.na(rating))

# data frames 
orgin_dst <- portal |> 
  dplyr::mutate(
    window = ifelse(transfer_date < as.POSIXct("2025-04-01"), "Winter", "Spring")
  ) |> 
  dplyr::filter(!is.na(origin) & !is.na(destination)) |>
  dplyr::count(origin, destination, sort = TRUE)
```
:::


### Portal plots 


::: {.cell}

```{.r .cell-code}
portal_plot <- portal |> 
  ggplot2::ggplot(ggplot2::aes(x = rating, order = rating, fill = window)) +
  ggdist::geom_dots(layout = "bar", group = NA, color = NA) +
  ggplot2::scale_fill_manual(
    values = c("Spring" = "#e4572e", "Winter" = "#6a7fd1")
  ) +
  ggplot2::scale_x_continuous(breaks = seq(0.75, 1.00, 0.05), limits = c(0.75, 1.00)) +
  ggplot2::labs(
    title = "College Football Transfer Portal  \nRatings by Window  \n<span style='color:#e4572e;'>Spring</span> and <span style='color:#6a7fd1; font-weight:bold'>Winter</span>",
    subtitle = "Each dot represents players that entered the portal ahead of the 2025 season.  \nDots are ordered by 247Sports Rating and grouped by the window when the player entered.",
     x = "<--- Lower Rating | Higher Rating --->",
    y = "",
    caption = "Only shows players with a 247Sports rating  \nViz by Chris at Bless your chart | data via cfbfastR and 247Sports.com | April 21, 2025"
  ) +
  hrbrthemes::theme_ipsum_rc() +
  ggplot2::theme(
    plot.title = ggtext::element_markdown(
      hjust = 0.5,
      size = 20,
      family = "Roboto Condensed"
    ),
    plot.subtitle = ggtext::element_markdown(
