    axis.text.y = ggplot2::element_blank(),
    plot.caption = ggplot2::element_text(face = "plain", size = 8, "Roboto Condensed")
  ) +
    ggplot2::annotate(
    geom = "label",
    x = 0.985,
    y = .47,
    color = "#333333",
    fill = "#e4572e",
    label = "Nico Iamaleava  \nTennessee QB  \nApril 12, 2025",
