### Table by position and window


::: {.cell}

```{.r .cell-code}
portal_summary <- portal  |>
  dplyr::mutate(position = dplyr::if_else(position == "DT", "DL", position), 
                position = dplyr::if_else(position %in% c("P", "K", "LS"), "ST", position)) |>
  dplyr::mutate(rating = as.numeric(rating)) |>
  dplyr::filter(!is.na(rating)) |>
  dplyr::group_by(window, position) |>
  dplyr::summarise(
    Best = max(rating),
    Median = median(rating),
    Worst = min(rating),
    Total = dplyr::n(),
    .groups = "drop"
  )

position_order <- portal_summary |>
  dplyr::group_by(window) |>
  dplyr::arrange(desc(Total), .by_group = TRUE) |>
  dplyr::mutate(position = factor(position, levels = unique(position))) 


portal_header <-glue::glue(
  "<div style='display: flex; justify-content: space-between; align-items: center;'>
      <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-football-college.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>Transfer Portal: 247Sports Ratings by Position</span>
       <span style='font-size: 14px; font-weight: normal; display: block; text-align: center;'>Best, worst, and median ratings for players in the portal ahead of the 2025 season.</span>
     </div>
     <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-football-college.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)


portal_table <- position_order |>
  tidyr::pivot_longer(
    cols = c(Best, Median, Worst, Total),
    names_to = "stat",
    values_to = "value"
  ) |>
  tidyr::pivot_wider(
    names_from = position,
    values_from = value
  ) |>
  dplyr::arrange(window, match(stat, c("Best", "Median", "Worst", "Total"))) |>
  gt::gt(groupname_col = "window") |> 
  gtUtils::gt_theme_gtutils() |> 
    gt::cols_label(
    stat = ""
  ) |> 
    gtUtils::gt_border_grid(color = "black",
                          weight = 0.5,
                          include_labels = FALSE) |> 
  gtExtras::gt_add_divider(
    columns = c(stat),
    sides = "right",
    color = "black"
  ) |> 
  gt::data_color(
    columns = c(-stat),
    rows = c(1:3, 5:7), 
    direction = c("column"),
    method = c("numeric"),
    palette = c("#d7191c", "#fdae61", 
                "#ffffbf", "#a6d96a", 
                "#1a9641"),
    alpha = 0.6
  ) |> 
  gt::cols_align(stat, align = "left") |> 
  gt::fmt_number(
    columns = c(-stat),
    rows = c(1:3, 5:7), 
    decimals = 2
  ) |> 
    gt::fmt_number(
    columns = c(-stat),
    rows = c(4, 8), 
    decimals = 0
  ) |> 
  gt::tab_header(title = gt::html(portal_header)) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>Data via cfbfastR | theme via {gtUtils} <br>
        Ratings provided by 247Sports and only surfaces players with an actual rating<br>
        Groups specialists together (K, P, LS) into one position group (ST)<br>
        Orders positions by the total number of players that entered the portal from the position<br>
        <hr><b>Table by Chris at Bless your chart | data from April 21, 2025</b>"
      )
  ) |>
  gtUtils::gt_border_bars_bottom(c("#636363", "#969696", "#cccccc")) |> 
  gt::tab_options(table.width = gt::px(675)) |>
  gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |> 
  gt::tab_style(
    style = list(
      gt::cell_text(font = gt::google_font("Signika Negative"),
                    size = gt::px(14)
      )
    ),
    locations = gt::cells_body(
      rows = gt::everything(),
      columns = gt::everything()
    )
  ) |> 
    gt::tab_style(
    locations = gt::cells_row_groups(),
    style = list(
      gt::cell_text(
        font = gt::google_font("Signika Negative"),
        weight = 850,
        size = gt::px(16),
        color = "black",
        align = "left"
      ),
      gt::cell_fill(
        color = "#C5C5FF"
      )
    )
  ) 


gtUtils::gt_save_crop(
  portal_table,
  file = "portal_tbl.png",
  whitespace = 40,
  bg = "#FFFDF5"
)

portal_table  
